import sys
import subprocess

def create_archive(dir_path, format):
    if format == "tar.gz":
        command = ["tar", "-czf", f"{dir_path}.tar.gz", dir_path]
    elif format == "tar.bz2":
        command = ["tar", "-jcf", f"{dir_path}.tar.bz2", dir_path]
    elif format == "zip":
        command = ["zip", f"{dir_path}.zip", dir_path]
    elif format == "7z":
        command = ["7z", f"a", "-t7z", f"{dir_path}.7z", dir_path]
    else:
        print("Invalid archive format. Supported formats are tar.gz, tar.bz2, zip, 7z.")
        return

    subprocess.run(command)

if __name__ == "__main__":
    if len(sys.argv) != 3:
        print("Usage: python backup_script.py <directory_path> <archive_format>")
    else:
        create_archive(sys.argv[1], sys.argv[2])